import{_ as a,c as i,o as e,ag as o}from"./chunks/framework.dvv-DFtf.js";const c=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),r={name:"guide/faq.md"};function t(h,l,n,s,q,u){return e(),i("div",null,[...l[0]||(l[0]=[o('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><p>这里收集了用户在使用二维码生成器时经常遇到的问题和解答。</p><h2 id="安装相关" tabindex="-1">安装相关 <a class="header-anchor" href="#安装相关" aria-label="Permalink to &quot;安装相关&quot;">​</a></h2><h3 id="q-如何安装扩展" tabindex="-1">Q: 如何安装扩展？ <a class="header-anchor" href="#q-如何安装扩展" aria-label="Permalink to &quot;Q: 如何安装扩展？&quot;">​</a></h3><p><strong>A:</strong> 有两种安装方式：</p><ol><li><p><strong>从 Chrome 网上应用店安装</strong>（推荐）：</p><ul><li>访问 Chrome 网上应用店</li><li>搜索&quot;二维码生成器&quot;</li><li>点击&quot;添加至 Chrome&quot;</li></ul></li><li><p><strong>开发者模式安装</strong>：</p><ul><li>访问 <code>chrome://extensions/</code></li><li>开启&quot;开发者模式&quot;</li><li>点击&quot;加载已解压的扩展程序&quot;</li><li>选择项目目录</li></ul></li></ol><h3 id="q-安装后看不到扩展图标" tabindex="-1">Q: 安装后看不到扩展图标？ <a class="header-anchor" href="#q-安装后看不到扩展图标" aria-label="Permalink to &quot;Q: 安装后看不到扩展图标？&quot;">​</a></h3><p><strong>A:</strong> 请检查以下几点：</p><ul><li>确认扩展已成功安装（在 <code>chrome://extensions/</code> 中查看）</li><li>确认扩展已启用（开关处于打开状态）</li><li>点击浏览器工具栏的扩展图标（可能需要点击&quot;拼图&quot;图标查看所有扩展）</li></ul><h3 id="q-支持哪些浏览器" tabindex="-1">Q: 支持哪些浏览器？ <a class="header-anchor" href="#q-支持哪些浏览器" aria-label="Permalink to &quot;Q: 支持哪些浏览器？&quot;">​</a></h3><p><strong>A:</strong> 支持以下浏览器：</p><ul><li>Chrome 88 及以上版本</li><li>Edge 88 及以上版本</li><li>其他基于 Chromium 的浏览器 88+</li></ul><h2 id="使用相关" tabindex="-1">使用相关 <a class="header-anchor" href="#使用相关" aria-label="Permalink to &quot;使用相关&quot;">​</a></h2><h3 id="q-如何生成当前页面的二维码" tabindex="-1">Q: 如何生成当前页面的二维码？ <a class="header-anchor" href="#q-如何生成当前页面的二维码" aria-label="Permalink to &quot;Q: 如何生成当前页面的二维码？&quot;">​</a></h3><p><strong>A:</strong> 有两种方式：</p><ol><li>点击浏览器工具栏中的扩展图标</li><li>在页面空白处右键，选择&quot;生成二维码&quot;</li></ol><h3 id="q-如何为选中的文本生成二维码" tabindex="-1">Q: 如何为选中的文本生成二维码？ <a class="header-anchor" href="#q-如何为选中的文本生成二维码" aria-label="Permalink to &quot;Q: 如何为选中的文本生成二维码？&quot;">​</a></h3><p><strong>A:</strong></p><ol><li>在网页中选中需要转换的文本</li><li>右键点击选中的文本</li><li>在右键菜单中选择&quot;生成二维码&quot;</li></ol><h3 id="q-如何为链接生成二维码" tabindex="-1">Q: 如何为链接生成二维码？ <a class="header-anchor" href="#q-如何为链接生成二维码" aria-label="Permalink to &quot;Q: 如何为链接生成二维码？&quot;">​</a></h3><p><strong>A:</strong></p><ol><li>在网页中找到需要生成二维码的链接</li><li>右键点击该链接</li><li>在右键菜单中选择&quot;生成二维码&quot;</li></ol><h3 id="q-如何复制-url" tabindex="-1">Q: 如何复制 URL？ <a class="header-anchor" href="#q-如何复制-url" aria-label="Permalink to &quot;Q: 如何复制 URL？&quot;">​</a></h3><p><strong>A:</strong> 在二维码面板中：</p><ol><li>找到 URL 显示区域</li><li>点击&quot;复制&quot;按钮</li><li>URL 已复制到剪贴板</li></ol><p>您也可以点击 URL 文本区域快速选中完整 URL，然后手动复制。</p><h3 id="q-如何下载二维码图片" tabindex="-1">Q: 如何下载二维码图片？ <a class="header-anchor" href="#q-如何下载二维码图片" aria-label="Permalink to &quot;Q: 如何下载二维码图片？&quot;">​</a></h3><p><strong>A:</strong></p><ol><li>在二维码面板中，将鼠标悬停在二维码上方</li><li>点击出现的&quot;下载&quot;按钮</li><li>二维码图片自动下载到默认下载目录</li></ol><h3 id="q-如何关闭二维码面板" tabindex="-1">Q: 如何关闭二维码面板？ <a class="header-anchor" href="#q-如何关闭二维码面板" aria-label="Permalink to &quot;Q: 如何关闭二维码面板？&quot;">​</a></h3><p><strong>A:</strong> 有三种方式：</p><ol><li>点击面板右上角的关闭按钮（×）</li><li>点击面板外的遮罩层</li><li>按键盘上的 ESC 键</li></ol><h2 id="功能相关" tabindex="-1">功能相关 <a class="header-anchor" href="#功能相关" aria-label="Permalink to &quot;功能相关&quot;">​</a></h2><h3 id="q-支持哪些内容类型" tabindex="-1">Q: 支持哪些内容类型？ <a class="header-anchor" href="#q-支持哪些内容类型" aria-label="Permalink to &quot;Q: 支持哪些内容类型？&quot;">​</a></h3><p><strong>A:</strong> 支持以下内容类型：</p><ul><li>网页 URL</li><li>纯文本</li><li>链接地址</li><li>其他可编码的文本内容</li></ul><h3 id="q-二维码有内容长度限制吗" tabindex="-1">Q: 二维码有内容长度限制吗？ <a class="header-anchor" href="#q-二维码有内容长度限制吗" aria-label="Permalink to &quot;Q: 二维码有内容长度限制吗？&quot;">​</a></h3><p><strong>A:</strong> 是的，二维码有内容长度限制：</p><ul><li>不同纠错级别支持的内容长度不同</li><li>过长的文本可能无法生成二维码</li><li>建议将超长内容分段处理</li></ul><h3 id="q-支持自定义二维码样式吗" tabindex="-1">Q: 支持自定义二维码样式吗？ <a class="header-anchor" href="#q-支持自定义二维码样式吗" aria-label="Permalink to &quot;Q: 支持自定义二维码样式吗？&quot;">​</a></h3><p><strong>A:</strong> 目前不支持自定义样式，但这是我们的未来计划之一。未来版本可能会支持：</p><ul><li>自定义二维码颜色</li><li>调整二维码大小</li><li>选择二维码样式模板</li></ul><h3 id="q-支持历史记录吗" tabindex="-1">Q: 支持历史记录吗？ <a class="header-anchor" href="#q-支持历史记录吗" aria-label="Permalink to &quot;Q: 支持历史记录吗？&quot;">​</a></h3><p><strong>A:</strong> 目前不支持历史记录功能，但这是我们的未来计划之一。</p><h2 id="问题排查" tabindex="-1">问题排查 <a class="header-anchor" href="#问题排查" aria-label="Permalink to &quot;问题排查&quot;">​</a></h2><h3 id="q-二维码无法生成" tabindex="-1">Q: 二维码无法生成？ <a class="header-anchor" href="#q-二维码无法生成" aria-label="Permalink to &quot;Q: 二维码无法生成？&quot;">​</a></h3><p><strong>A:</strong> 请尝试以下方法：</p><ol><li>检查内容是否过长</li><li>确认浏览器版本是否支持（Chrome 88+）</li><li>尝试刷新页面后重试</li><li>检查扩展是否已启用</li><li>重新加载扩展</li></ol><h3 id="q-二维码无法扫描" tabindex="-1">Q: 二维码无法扫描？ <a class="header-anchor" href="#q-二维码无法扫描" aria-label="Permalink to &quot;Q: 二维码无法扫描？&quot;">​</a></h3><p><strong>A:</strong> 请检查以下几点：</p><ol><li>确保二维码清晰可见</li><li>检查屏幕亮度是否足够</li><li>尝试下载二维码图片后扫描</li><li>确保扫描设备摄像头正常工作</li></ol><h3 id="q-右键菜单不显示" tabindex="-1">Q: 右键菜单不显示？ <a class="header-anchor" href="#q-右键菜单不显示" aria-label="Permalink to &quot;Q: 右键菜单不显示？&quot;">​</a></h3><p><strong>A:</strong> 请尝试以下方法：</p><ol><li>确认扩展已正确安装</li><li>检查扩展是否已启用</li><li>尝试重新加载扩展</li><li>刷新当前网页</li><li>重启浏览器</li></ol><h3 id="q-扩展图标点击无反应" tabindex="-1">Q: 扩展图标点击无反应？ <a class="header-anchor" href="#q-扩展图标点击无反应" aria-label="Permalink to &quot;Q: 扩展图标点击无反应？&quot;">​</a></h3><p><strong>A:</strong> 请检查：</p><ol><li>确认扩展已启用</li><li>检查当前页面是否支持（某些特殊页面可能不支持）</li><li>查看浏览器控制台是否有错误信息</li><li>尝试重新加载扩展</li></ol><h3 id="q-复制功能不工作" tabindex="-1">Q: 复制功能不工作？ <a class="header-anchor" href="#q-复制功能不工作" aria-label="Permalink to &quot;Q: 复制功能不工作？&quot;">​</a></h3><p><strong>A:</strong> 请检查：</p><ol><li>确认浏览器支持 Clipboard API</li><li>检查浏览器权限设置</li><li>尝试手动选择文本复制</li><li>查看浏览器控制台是否有错误</li></ol><h2 id="技术相关" tabindex="-1">技术相关 <a class="header-anchor" href="#技术相关" aria-label="Permalink to &quot;技术相关&quot;">​</a></h2><h3 id="q-数据会上传到服务器吗" tabindex="-1">Q: 数据会上传到服务器吗？ <a class="header-anchor" href="#q-数据会上传到服务器吗" aria-label="Permalink to &quot;Q: 数据会上传到服务器吗？&quot;">​</a></h3><p><strong>A:</strong> 不会。所有处理都在本地完成：</p><ul><li>二维码生成在浏览器本地完成</li><li>不收集任何用户数据</li><li>不上传任何信息到服务器</li><li>完全保护用户隐私</li></ul><h3 id="q-扩展占用多少资源" tabindex="-1">Q: 扩展占用多少资源？ <a class="header-anchor" href="#q-扩展占用多少资源" aria-label="Permalink to &quot;Q: 扩展占用多少资源？&quot;">​</a></h3><p><strong>A:</strong> 扩展非常轻量：</p><ul><li>安装包大小：约 100KB</li><li>内存占用：极小</li><li>不影响浏览器性能</li><li>仅在需要时加载资源</li></ul><h3 id="q-支持离线使用吗" tabindex="-1">Q: 支持离线使用吗？ <a class="header-anchor" href="#q-支持离线使用吗" aria-label="Permalink to &quot;Q: 支持离线使用吗？&quot;">​</a></h3><p><strong>A:</strong> 完全支持离线使用：</p><ul><li>所有功能都在本地实现</li><li>不需要网络连接</li><li>可以离线生成二维码</li></ul><h2 id="其他问题" tabindex="-1">其他问题 <a class="header-anchor" href="#其他问题" aria-label="Permalink to &quot;其他问题&quot;">​</a></h2><h3 id="q-如何反馈问题或建议" tabindex="-1">Q: 如何反馈问题或建议？ <a class="header-anchor" href="#q-如何反馈问题或建议" aria-label="Permalink to &quot;Q: 如何反馈问题或建议？&quot;">​</a></h3><p><strong>A:</strong> 欢迎通过以下方式反馈：</p><ul><li>提交 <a href="https://gitee.com/mdsfe/qrcode-extension/issues" target="_blank" rel="noreferrer">Issue</a></li><li>参与项目贡献</li><li>分享使用体验</li></ul><h3 id="q-如何参与项目贡献" tabindex="-1">Q: 如何参与项目贡献？ <a class="header-anchor" href="#q-如何参与项目贡献" aria-label="Permalink to &quot;Q: 如何参与项目贡献？&quot;">​</a></h3><p><strong>A:</strong> 欢迎贡献代码：</p><ol><li>Fork 项目</li><li>创建功能分支</li><li>提交更改</li><li>发起 Pull Request</li></ol><h3 id="q-项目使用什么许可证" tabindex="-1">Q: 项目使用什么许可证？ <a class="header-anchor" href="#q-项目使用什么许可证" aria-label="Permalink to &quot;Q: 项目使用什么许可证？&quot;">​</a></h3><p><strong>A:</strong> 项目使用 MIT 许可证，您可以自由使用、修改和分发。</p><h3 id="q-未来会添加哪些功能" tabindex="-1">Q: 未来会添加哪些功能？ <a class="header-anchor" href="#q-未来会添加哪些功能" aria-label="Permalink to &quot;Q: 未来会添加哪些功能？&quot;">​</a></h3><p><strong>A:</strong> 我们计划添加以下功能：</p><ul><li>自定义二维码颜色</li><li>调整二维码大小</li><li>二维码预览功能</li><li>更多语言支持</li><li>二维码样式模板</li><li>历史记录功能</li></ul><hr><p>如果这里没有您要找的答案，请：</p><ul><li>查看 <a href="/guide/usage.html">使用指南</a></li><li>阅读 <a href="/guide/technical.html">技术文档</a></li><li>提交 <a href="https://gitee.com/mdsfe/qrcode-extension/issues" target="_blank" rel="noreferrer">Issue</a></li></ul>',85)])])}const p=a(r,[["render",t]]);export{c as __pageData,p as default};
